// scripts/upload-to-buffer.mjs
//
// Schedules the weekly social pack (generated by generate-social-content.mjs)
// to Buffer for automatic posting via Buffer's GraphQL API.
//
//   node scripts/upload-to-buffer.mjs
//
// Required env:
//   BUFFER_ACCESS_TOKEN          Buffer personal access token (Bearer)
//
// Optional env (auto-detected from /channels otherwise):
//   BUFFER_ORGANIZATION_ID       Buffer organization id
//   BUFFER_TWITTER_CHANNEL_ID    channel id for X / Twitter
//   BUFFER_INSTAGRAM_CHANNEL_ID  channel id for Instagram
//
// Common flags:
//   --dry-run                       don't actually post; print what would be sent
//   --list-profiles | --list-channels   print connected channels and exit
//   --platforms=twitter,instagram   default: twitter,instagram
//   --start-date=YYYY-MM-DD         first post date; default: tomorrow (in --tz)
//   --hour=16                       hour-of-day in --tz; default 16 (4 PM)
//   --tz=America/New_York           IANA timezone; default America/New_York
//   --image-base-url=URL            where day-N.png is publicly hosted;
//                                   default https://plixfy.com/social/weekly/
//   --copy-images                   also copy the PNGs into public/social/weekly/
//                                   so Vercel will serve them after `git push`
//   --skip-images                   schedule with a link asset only (no image)
//   --scheduling-type=notification|automatic
//                                   default: notification (Buffer free tier
//                                   sends a phone-push reminder; switch to
//                                   `automatic` if your plan supports it).
//   --share-mode=customScheduled|addToQueue|shareNext|recommendedTime
//                                   default: customScheduled (uses --hour/--tz)
//   --organization-id=ID            override Buffer org id (else first one).
//
// API: https://graph.buffer.com/graphql
//      Auth: Authorization: Bearer <token>

import { readFileSync, writeFileSync, copyFileSync, mkdirSync, existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(here, '..');
const weeklyDir = join(repoRoot, 'scripts', 'output', 'weekly');
const publicSocialDir = join(repoRoot, 'public', 'social', 'weekly');

// ── Args ────────────────────────────────────────────────────────────────
const args = Object.fromEntries(
  process.argv.slice(2).map((a) => {
    const m = a.match(/^--([^=]+)(?:=(.*))?$/);
    return m ? [m[1], m[2] ?? true] : [a, true];
  }),
);

const DRY_RUN = !!args['dry-run'];
const LIST_ONLY = !!args['list-profiles'] || !!args['list-channels'];
const COPY_IMAGES = !!args['copy-images'];
const SKIP_IMAGES = !!args['skip-images'];
const HOUR = Number(args.hour) || 16;
const TZ = args.tz || 'America/New_York';
const IMAGE_BASE_URL = (args['image-base-url'] || 'https://plixfy.com/social/weekly/').replace(/\/?$/, '/');
const PLATFORMS = (args.platforms || 'twitter,instagram')
  .split(',')
  .map((s) => s.trim().toLowerCase())
  .filter(Boolean);
const SCHEDULING_TYPE = args['scheduling-type'] || 'notification';
const SHARE_MODE = args['share-mode'] || 'customScheduled';

const TOKEN = process.env.BUFFER_ACCESS_TOKEN;
if (!TOKEN) {
  console.error('ERROR: BUFFER_ACCESS_TOKEN env var is required.');
  console.error('Get one at https://publish.buffer.com/account/apps → Personal Access Token.');
  process.exit(1);
}

const CHANNEL_ID_BY_SERVICE = {
  twitter: process.env.BUFFER_TWITTER_CHANNEL_ID || null,
  instagram: process.env.BUFFER_INSTAGRAM_CHANNEL_ID || null,
};
const ORG_ID_OVERRIDE = args['organization-id'] || process.env.BUFFER_ORGANIZATION_ID || null;

function todayIsoIn(tz) {
  const dtf = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return dtf.format(new Date());
}
function addDaysIso(iso, days) {
  const [y, m, d] = iso.split('-').map(Number);
  const utc = Date.UTC(y, m - 1, d) + days * 86_400_000;
  return new Date(utc).toISOString().slice(0, 10);
}
const START_DATE = args['start-date'] || addDaysIso(todayIsoIn(TZ), 1);

// ── GraphQL client ─────────────────────────────────────────────────────

const GRAPHQL_ENDPOINT = 'https://graph.buffer.com/graphql';

async function gql({ query, variables, opName }) {
  const res = await fetch(GRAPHQL_ENDPOINT, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      authorization: `Bearer ${TOKEN}`,
    },
    body: JSON.stringify({ query, variables, operationName: opName }),
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json.errors) {
    const msg = json.errors?.map((e) => e.message).join('; ') || `HTTP ${res.status}`;
    throw new Error(`GraphQL ${opName || ''} failed: ${msg}`);
  }
  return json.data;
}

// ── Schema operations ──────────────────────────────────────────────────

const Q_ACCOUNT = `
  query Account {
    account {
      id
      email
      organizations { id name }
    }
  }
`;

const Q_CHANNELS = `
  query Channels($organizationId: OrganizationId!) {
    channels(input: { organizationId: $organizationId }) {
      id
      service
      name
      displayName
      isDisconnected
      isLocked
    }
  }
`;

const M_CREATE_POST = `
  mutation CreatePost($input: CreatePostInput!) {
    createPost(input: $input) {
      __typename
      ... on PostActionSuccess {
        post { id status dueAt channelId }
      }
      ... on NotFoundError { message }
      ... on UnauthorizedError { message }
      ... on UnexpectedError { message }
      ... on LimitReachedError { message }
      ... on InvalidInputError { message }
      ... on RestProxyError { message code }
    }
  }
`;

// ── Timezone-aware scheduler ───────────────────────────────────────────

function wallClockToUTC(dateIso, hour, minute, tz) {
  const [y, m, d] = dateIso.split('-').map(Number);
  const guessUTC = Date.UTC(y, m - 1, d, hour, minute, 0);
  const dtf = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    hourCycle: 'h23',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });
  const parts = Object.fromEntries(
    dtf.formatToParts(new Date(guessUTC)).map((p) => [p.type, p.value]),
  );
  const wallAsUTC = Date.UTC(
    Number(parts.year),
    Number(parts.month) - 1,
    Number(parts.day),
    Number(parts.hour),
    Number(parts.minute),
    Number(parts.second),
  );
  const offset = wallAsUTC - guessUTC;
  return new Date(guessUTC - offset);
}

// ── Channel resolution ─────────────────────────────────────────────────

const SERVICE_ALIAS = {
  x: 'twitter',
  twitter: 'twitter',
  instagram: 'instagram',
  ig: 'instagram',
};

function normaliseService(s) {
  return SERVICE_ALIAS[String(s).toLowerCase()] || String(s).toLowerCase();
}

function pickOrganizationId(account) {
  if (ORG_ID_OVERRIDE) return ORG_ID_OVERRIDE;
  const orgs = account?.organizations || [];
  if (orgs.length === 0) {
    throw new Error('No organizations on this Buffer account.');
  }
  if (orgs.length > 1) {
    const names = orgs.map((o) => `${o.name || o.id} (${o.id})`).join(', ');
    console.warn(`  warn: multiple organizations (${names}). Using first; set --organization-id to override.`);
  }
  return orgs[0].id;
}

function resolveChannelsForServices(channels) {
  const byService = {};
  for (const c of channels) {
    if (c.isDisconnected) continue;
    const svc = normaliseService(c.service);
    if (!byService[svc]) byService[svc] = [];
    byService[svc].push(c);
  }
  const resolved = {};
  for (const wanted of PLATFORMS) {
    const svc = normaliseService(wanted);
    const overrideId = CHANNEL_ID_BY_SERVICE[svc];
    if (overrideId) {
      resolved[svc] = { id: overrideId, source: 'env', service: svc };
      continue;
    }
    const candidates = byService[svc] || [];
    if (candidates.length === 0) {
      console.warn(`  warn: no connected ${svc} channel found; skipping that platform.`);
      continue;
    }
    if (candidates.length > 1) {
      const names = candidates
        .map((c) => `${c.displayName || c.name} (${c.id})`)
        .join(', ');
      console.warn(`  warn: multiple ${svc} channels (${names}). Using first; set BUFFER_${svc.toUpperCase()}_CHANNEL_ID to override.`);
    }
    const c = candidates[0];
    resolved[svc] = {
      id: c.id,
      source: 'auto',
      service: svc,
      name: c.displayName || c.name,
    };
  }
  return resolved;
}

// ── Image staging ──────────────────────────────────────────────────────

function copyImagesToPublic(entries) {
  mkdirSync(publicSocialDir, { recursive: true });
  for (const e of entries) {
    const src = join(weeklyDir, e.image);
    const dst = join(publicSocialDir, e.image);
    if (!existsSync(src)) {
      console.warn(`  warn: ${src} missing — generate-social-content.mjs first.`);
      continue;
    }
    copyFileSync(src, dst);
    console.log(`  copied ${e.image} → public/social/weekly/`);
  }
  console.log('  → commit + push to deploy these to Vercel before Buffer fetches them.');
}

// ── Build CreatePostInput ──────────────────────────────────────────────

function buildCreatePostInput({ entry, channelId, service, scheduledAtUTC }) {
  const text = service === 'twitter' ? entry.twitter : entry.instagram;
  const imageUrl = SKIP_IMAGES ? null : `${IMAGE_BASE_URL}${entry.image}`;

  // `assets` is required (non-null list). Image asset preferred; fall back
  // to a link asset (with game URL) when image is skipped or unavailable.
  const assets = imageUrl
    ? [{ image: { url: imageUrl, thumbnailUrl: imageUrl } }]
    : [{ link: { url: entry.game.url, title: entry.game.title, description: text.slice(0, 200) } }];

  const input = {
    channelId,
    text,
    assets,
    schedulingType: SCHEDULING_TYPE, // 'notification' | 'automatic'
    mode: SHARE_MODE, // 'customScheduled' for scheduled-at-time
    aiAssisted: true,
    source: 'plixfy-weekly-generator',
  };
  if (SHARE_MODE === 'customScheduled') {
    input.dueAt = scheduledAtUTC.toISOString();
  }
  return input;
}

function unwrapCreatePostResult(payload) {
  if (!payload) return { ok: false, error: 'empty payload' };
  const tn = payload.__typename;
  if (tn === 'PostActionSuccess') {
    return { ok: true, post: payload.post };
  }
  return {
    ok: false,
    error: `${tn || 'UnknownError'}${payload.message ? ': ' + payload.message : ''}${payload.code ? ' [' + payload.code + ']' : ''}`,
  };
}

// ── Main ───────────────────────────────────────────────────────────────

async function main() {
  console.log('Buffer scheduler (GraphQL)');
  console.log(`  dry-run: ${DRY_RUN}    platforms: ${PLATFORMS.join(',')}    start-date: ${START_DATE}    ${HOUR}:00 ${TZ}`);
  console.log(`  scheduling: ${SCHEDULING_TYPE}    mode: ${SHARE_MODE}`);
  console.log(`  image base: ${SKIP_IMAGES ? '(none)' : IMAGE_BASE_URL}`);

  // Probe token + fetch account/org id.
  let account;
  try {
    const data = await gql({ query: Q_ACCOUNT, opName: 'Account' });
    account = data.account;
    console.log(`  buffer user: ${account.email || account.id}`);
  } catch (err) {
    console.error(`  ERROR: ${err.message}`);
    console.error('  Check your BUFFER_ACCESS_TOKEN at https://publish.buffer.com/account/apps');
    process.exit(1);
  }

  const organizationId = pickOrganizationId(account);
  console.log(`  organization: ${organizationId}`);

  // Fetch channels.
  const { channels } = await gql({
    query: Q_CHANNELS,
    variables: { organizationId },
    opName: 'Channels',
  });

  if (LIST_ONLY) {
    console.log('Connected channels:');
    for (const c of channels || []) {
      const flags = [c.isDisconnected && 'disconnected', c.isLocked && 'locked'].filter(Boolean).join(', ');
      console.log(`  - ${String(c.service).padEnd(14)} ${(c.displayName || c.name || '').padEnd(28)}  id=${c.id}${flags ? '  [' + flags + ']' : ''}`);
    }
    return;
  }

  // Load posts.json.
  const postsPath = join(weeklyDir, 'posts.json');
  if (!existsSync(postsPath)) {
    console.error(`ERROR: ${postsPath} not found. Run generate-social-content.mjs first.`);
    process.exit(1);
  }
  const pack = JSON.parse(readFileSync(postsPath, 'utf8'));
  const entries = pack.entries || [];
  if (entries.length === 0) {
    console.error('ERROR: posts.json has no entries.');
    process.exit(1);
  }
  console.log(`  loaded ${entries.length} entries from posts.json`);

  // Optionally stage images for plixfy.com.
  if (COPY_IMAGES && !SKIP_IMAGES) {
    copyImagesToPublic(entries);
  }

  // Verify image URLs are reachable (skip check on dry-run).
  if (!SKIP_IMAGES && !DRY_RUN) {
    const sampleUrl = `${IMAGE_BASE_URL}${entries[0].image}`;
    try {
      const r = await fetch(sampleUrl, { method: 'HEAD' });
      if (!r.ok) {
        console.warn(`  warn: HEAD ${sampleUrl} → ${r.status}. Buffer needs publicly reachable image URLs.`);
        console.warn(`         Re-run with --copy-images and deploy, or pass --image-base-url=… or --skip-images.`);
      } else {
        console.log(`  image base reachable (HEAD ${sampleUrl} → ${r.status})`);
      }
    } catch (err) {
      console.warn(`  warn: could not HEAD-check ${sampleUrl}: ${err.message}`);
    }
  }

  // Resolve channels for requested platforms.
  const resolved = resolveChannelsForServices(channels || []);
  if (Object.keys(resolved).length === 0) {
    console.error('ERROR: no usable channels. Connect at least one Twitter or Instagram channel in Buffer.');
    process.exit(1);
  }
  for (const [svc, c] of Object.entries(resolved)) {
    console.log(`  ${svc.padEnd(10)} → ${c.id}  (${c.source}${c.name ? ', ' + c.name : ''})`);
  }

  // Schedule each entry on each resolved channel.
  const results = [];
  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];
    const dateIso = addDaysIso(START_DATE, i);
    const scheduledAtUTC = wallClockToUTC(dateIso, HOUR, 0, TZ);
    console.log(`\nDay ${i + 1}/${entries.length} — ${dateIso} ${String(HOUR).padStart(2, '0')}:00 ${TZ}  (${scheduledAtUTC.toISOString()})`);
    console.log(`  game: ${entry.game.title}`);

    for (const [svc, channel] of Object.entries(resolved)) {
      const input = buildCreatePostInput({
        entry,
        channelId: channel.id,
        service: svc,
        scheduledAtUTC,
      });
      const summary = {
        day: entry.day,
        date: dateIso,
        scheduledAtUTC: scheduledAtUTC.toISOString(),
        service: svc,
        channelId: channel.id,
        textLength: input.text.length,
        image: SKIP_IMAGES ? null : `${IMAGE_BASE_URL}${entry.image}`,
        link: entry.game.url,
      };

      if (DRY_RUN) {
        console.log(`  [dry-run] ${svc}: would createPost (${input.text.length} chars${input.assets[0].image ? ', +image' : ', +link'})`);
        results.push({ ...summary, status: 'dry-run' });
        continue;
      }

      try {
        const data = await gql({
          query: M_CREATE_POST,
          variables: { input },
          opName: 'CreatePost',
        });
        const result = unwrapCreatePostResult(data?.createPost);
        if (result.ok) {
          console.log(`  ${svc}: scheduled (post id=${result.post.id}, status=${result.post.status})`);
          results.push({ ...summary, status: 'scheduled', postId: result.post.id, postStatus: result.post.status, dueAt: result.post.dueAt });
        } else {
          console.error(`  ${svc}: FAILED — ${result.error}`);
          results.push({ ...summary, status: 'error', error: result.error });
        }
      } catch (err) {
        console.error(`  ${svc}: FAILED — ${err.message}`);
        results.push({ ...summary, status: 'error', error: err.message });
      }
    }
  }

  // Write schedule log.
  const logPath = join(weeklyDir, 'buffer-schedule.json');
  writeFileSync(
    logPath,
    JSON.stringify(
      {
        ranAt: new Date().toISOString(),
        api: 'graphql',
        dryRun: DRY_RUN,
        startDate: START_DATE,
        hour: HOUR,
        tz: TZ,
        schedulingType: SCHEDULING_TYPE,
        shareMode: SHARE_MODE,
        organizationId,
        platforms: Object.keys(resolved),
        imageBaseUrl: SKIP_IMAGES ? null : IMAGE_BASE_URL,
        results,
      },
      null,
      2,
    ),
  );

  const ok = results.filter((r) => r.status === 'scheduled').length;
  const failed = results.filter((r) => r.status === 'error').length;
  const dry = results.filter((r) => r.status === 'dry-run').length;
  console.log(`\nDone. scheduled=${ok}  failed=${failed}  dry-run=${dry}`);
  console.log(`Log: ${logPath}`);
  if (failed > 0) process.exit(2);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
